  result <- convert(html = "<table><thead><tr><th align=\"left\">Left</th><th align=\"center\">Center</th><th align=\"right\">Right</th></tr></thead><tbody><tr><td>L</td><td>C</td><td>R</td></tr></tbody></table>", options = ConversionOptions$default())
  expect_true(if (is.character(result$content)) length(result$content) > 0 && any(nchar(result$content) > 0) else length(result$content) > 0)
  expect_true(any(grepl("Left", result$content, fixed = TRUE)))
  expect_true(any(grepl("Center", result$content, fixed = TRUE)))
  expect_true(any(grepl("Right", result$content, fixed = TRUE)))
  expect_true(any(grepl("L", result$content, fixed = TRUE)))
  expect_true(any(grepl("C", result$content, fixed = TRUE)))
  expect_true(any(grepl("R", result$content, fixed = TRUE)))
  expect_true(any(grepl("|", result$content, fixed = TRUE)))
})

test_that("table_with_colspan: Table with colspan attribute in a header cell", {
  result <- convert(html = "<table><thead><tr><th colspan=\"2\">Full Name</th></tr></thead><tbody><tr><td>John</td><td>Doe</td></tr></tbody></table>", options = ConversionOptions$default())
  expect_true(if (is.character(result$content)) length(result$content) > 0 && any(nchar(result$content) > 0) else length(result$content) > 0)
  expect_true(any(grepl("Full Name", result$content, fixed = TRUE)))
  expect_true(any(grepl("John", result$content, fixed = TRUE)))
  expect_true(any(grepl("Doe", result$content, fixed = TRUE)))
})

test_that("unordered_list: Unordered list", {
  result <- convert(html = "<ul><li>Item 1</li><li>Item 2</li><li>Item 3</li></ul>", options = ConversionOptions$default())
  expect_true(any(grepl("- Item 1", result$content, fixed = TRUE)))
